import React, { useState, useEffect, useRef } from 'react';
import { Routes, Route, useNavigate } from 'react-router-dom';
import { MapContainer, TileLayer, Marker, Popup } from 'react-leaflet';
import L from 'leaflet';
import { useAuth } from '../App';
import api from '../api';

// Fix leaflet marker icons
delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon-2x.png',
  iconUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-icon.png',
  shadowUrl: 'https://unpkg.com/leaflet@1.9.4/dist/images/marker-shadow.png',
});

// ── Deficiency Card ───────────────────────────────────────────────────────────
function DefCard({ r }) {
  const [open, setOpen] = useState(false);
  return (
    <div style={{ background: '#fff', border: `1.5px solid ${r.color}30`, borderRadius: 12, overflow: 'hidden', marginBottom: 10 }}>
      <div style={{ padding: '1rem', borderBottom: open ? `1px solid ${r.color}20` : 'none' }}>
        <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 10 }}>
            <div style={{ width: 38, height: 38, borderRadius: 10, background: r.bg, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '1.3rem' }}>{r.icon}</div>
            <div>
              <div style={{ fontWeight: 700, fontSize: '0.95rem', color: r.color }}>{r.name}</div>
              <div style={{ fontSize: '0.72rem', color: '#6b7280' }}>ICD {r.icd} · {r.severity}</div>
            </div>
          </div>
          <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
            <span style={{ background: r.color, color: 'white', borderRadius: 20, padding: '3px 10px', fontSize: '0.75rem', fontWeight: 700 }}>{r.confidence}% match</span>
            <button onClick={() => setOpen(!open)} style={{ background: 'none', border: `1px solid ${r.color}40`, borderRadius: 8, color: r.color, cursor: 'pointer', padding: '4px 10px', fontSize: '0.75rem', fontWeight: 600 }}>
              {open ? 'Less ▲' : 'More ▼'}
            </button>
          </div>
        </div>
        <div style={{ marginTop: 8, fontSize: '0.78rem', color: '#6b7280', background: '#f9fafb', borderRadius: 8, padding: '6px 10px' }}>
          📍 {r.kenya_stat}
        </div>
        {r.matched_symptoms?.length > 0 && (
          <div style={{ marginTop: 8, display: 'flex', flexWrap: 'wrap', gap: 5 }}>
            {r.matched_symptoms.map(s => (
              <span key={s} style={{ background: `${r.color}12`, color: r.color, border: `1px solid ${r.color}30`, borderRadius: 12, padding: '2px 8px', fontSize: '0.7rem', fontWeight: 600 }}>✓ {s}</span>
            ))}
          </div>
        )}
      </div>

      {open && (
        <div style={{ padding: '1rem', background: '#fafafa' }}>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 12 }}>
            <div>
              <div style={{ fontSize: '0.72rem', fontWeight: 700, color: '#16a34a', textTransform: 'uppercase', marginBottom: 6 }}>🥬 Recommended Kenyan Foods</div>
              <ul style={{ paddingLeft: 16, fontSize: '0.82rem', lineHeight: 1.8, color: '#374151' }}>
                {r.foods_recommended.map(f => <li key={f}>{f}</li>)}
              </ul>
            </div>
            <div>
              <div style={{ fontSize: '0.72rem', fontWeight: 700, color: '#d97706', textTransform: 'uppercase', marginBottom: 6 }}>💡 Tips</div>
              <ul style={{ paddingLeft: 16, fontSize: '0.82rem', lineHeight: 1.8, color: '#374151' }}>
                {r.tips.map(t => <li key={t}>{t}</li>)}
              </ul>
              {r.foods_avoid?.length > 0 && (
                <>
                  <div style={{ fontSize: '0.72rem', fontWeight: 700, color: '#dc2626', textTransform: 'uppercase', margin: '8px 0 4px' }}>⚠️ Limit</div>
                  <ul style={{ paddingLeft: 16, fontSize: '0.82rem', lineHeight: 1.8, color: '#dc2626' }}>
                    {r.foods_avoid.map(f => <li key={f}>{f}</li>)}
                  </ul>
                </>
              )}
            </div>
          </div>
          <div style={{ marginTop: 10, background: '#fff', border: '1px solid #e5e7eb', borderRadius: 8, padding: '8px 12px' }}>
            <span style={{ fontSize: '0.72rem', fontWeight: 700, color: '#6b7280' }}>SUPPLEMENT GUIDANCE: </span>
            <span style={{ fontSize: '0.8rem', color: '#374151' }}>{r.supplement}</span>
          </div>
          <div style={{ marginTop: 8, background: '#fef2f2', border: '1px solid #fca5a5', borderRadius: 8, padding: '8px 12px', fontSize: '0.78rem', color: '#dc2626' }}>
            🏥 <strong>See a doctor if:</strong> {r.when_to_see_doctor}
          </div>
          <div style={{ marginTop: 6, fontSize: '0.7rem', color: '#9ca3af', fontStyle: 'italic' }}>
            AI assessment only. Confirm with blood tests. Always consult a licensed healthcare professional.
          </div>
        </div>
      )}
    </div>
  );
}

// ── Chatbot ───────────────────────────────────────────────────────────────────
function Chatbot({ user }) {
  const WELCOME = { id: 'w', type: 'ai', text: `Hello ${user?.name?.split(' ')[0] || ''}! 👋\n\nI'm MediHelp AI, your nutritional health assistant.\n\nDescribe your symptoms and I'll identify possible nutritional deficiencies — with Kenyan food solutions.\n\n**Try:** "I feel tired all the time, my hair is falling out and I get dizzy"\n\nWhat symptoms are you experiencing?`, results: null };
  const [messages, setMessages] = useState([WELCOME]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const endRef = useRef(null);

  useEffect(() => { endRef.current?.scrollIntoView({ behavior: 'smooth' }); }, [messages, loading]);

  const send = async () => {
    const text = input.trim();
    if (!text || loading) return;
    setInput('');
    setMessages(m => [...m, { id: Date.now(), type: 'user', text, results: null }]);
    setLoading(true);
    try {
      const res = await api.post('/api/analyze', { symptoms: text });
      const results = res.data.results;
      let reply = results.length > 0
        ? `I found **${results.length} potential deficiency risk${results.length > 1 ? 's' : ''}** based on your symptoms.\n\nYour top match: **${results[0].name}** (${results[0].confidence}% confidence).\n\nSee the detailed cards below. Remember to confirm with blood tests and consult your doctor.`
        : `I couldn't identify a specific deficiency from those symptoms. Try describing more details — for example:\n\n• Fatigue, hair loss, pale skin → possible iron deficiency\n• Bone pain, muscle weakness → possible Vitamin D\n• Night blindness → possible Vitamin A`;
      setMessages(m => [...m, { id: Date.now() + 1, type: 'ai', text: reply, results }]);
    } catch {
      setMessages(m => [...m, { id: Date.now() + 1, type: 'ai', text: 'Sorry, the analysis failed. Please check your connection and try again.', results: null }]);
    } finally { setLoading(false); }
  };

  const fmt = t => t.replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>').replace(/\n/g, '<br/>');

  return (
    <div style={{ display: 'flex', flexDirection: 'column', height: 'calc(100vh - 180px)', minHeight: 520 }}>
      {/* Header */}
      <div style={{ padding: '1rem 1.25rem', background: 'linear-gradient(135deg, #052e16, #16a34a)', color: 'white', borderRadius: '14px 14px 0 0', display: 'flex', alignItems: 'center', gap: 12 }}>
        <div style={{ width: 40, height: 40, borderRadius: '50%', background: 'rgba(255,255,255,0.15)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '1.3rem' }}>🩺</div>
        <div>
          <div style={{ fontWeight: 700, fontSize: '0.95rem' }}>MediHelp Nutrition AI</div>
          <div style={{ fontSize: '0.72rem', opacity: 0.8, display: 'flex', alignItems: 'center', gap: 5 }}>
            <span style={{ width: 6, height: 6, background: '#86efac', borderRadius: '50%', animation: 'pulse 2s infinite', display: 'inline-block' }} />
            Kenya Deficiency Specialist
          </div>
        </div>
        <button onClick={() => setMessages([WELCOME])} style={{ marginLeft: 'auto', background: 'rgba(255,255,255,0.15)', border: 'none', color: 'white', borderRadius: 8, padding: '5px 12px', cursor: 'pointer', fontSize: '0.78rem' }}>
          Clear
        </button>
      </div>

      {/* Messages */}
      <div style={{ flex: 1, overflowY: 'auto', padding: '1rem', background: '#f4f6fb', display: 'flex', flexDirection: 'column', gap: 12 }}>
        {messages.map(msg => (
          <div key={msg.id}>
            <div style={{ display: 'flex', gap: 8, justifyContent: msg.type === 'user' ? 'flex-end' : 'flex-start' }}>
              {msg.type === 'ai' && (
                <div style={{ width: 30, height: 30, borderRadius: '50%', background: 'linear-gradient(135deg, #16a34a, #15803d)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '0.8rem', flexShrink: 0 }}>🩺</div>
              )}
              <div style={{ maxWidth: '80%', padding: '0.7rem 1rem', borderRadius: msg.type === 'user' ? '16px 16px 4px 16px' : '16px 16px 16px 4px', background: msg.type === 'user' ? 'linear-gradient(135deg, #16a34a, #15803d)' : 'white', color: msg.type === 'user' ? 'white' : '#111827', border: msg.type === 'ai' ? '1px solid #e5e7eb' : 'none', fontSize: '0.88rem', lineHeight: 1.65, boxShadow: '0 2px 8px rgba(0,0,0,0.06)' }}>
                <span dangerouslySetInnerHTML={{ __html: fmt(msg.text) }} />
              </div>
              {msg.type === 'user' && (
                <div style={{ width: 30, height: 30, borderRadius: '50%', background: 'linear-gradient(135deg, #374151, #111827)', display: 'flex', alignItems: 'center', justifyContent: 'center', color: 'white', fontSize: '0.75rem', fontWeight: 700, flexShrink: 0 }}>
                  {(user?.name || 'U')[0].toUpperCase()}
                </div>
              )}
            </div>
            {msg.results?.length > 0 && (
              <div style={{ marginTop: 10, marginLeft: 38 }}>
                {msg.results.map(r => <DefCard key={r.id} r={r} />)}
              </div>
            )}
          </div>
        ))}
        {loading && (
          <div style={{ display: 'flex', gap: 8 }}>
            <div style={{ width: 30, height: 30, borderRadius: '50%', background: 'linear-gradient(135deg, #16a34a, #15803d)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '0.8rem' }}>🩺</div>
            <div style={{ padding: '0.7rem 1rem', background: 'white', border: '1px solid #e5e7eb', borderRadius: '16px 16px 16px 4px', display: 'flex', gap: 5, alignItems: 'center' }}>
              {[0,1,2].map(i => <span key={i} style={{ width: 7, height: 7, background: '#16a34a', borderRadius: '50%', animation: `bounce 1.2s ease-in-out ${i*0.2}s infinite`, display: 'inline-block' }} />)}
              <span style={{ marginLeft: 6, fontSize: '0.78rem', color: '#6b7280', fontStyle: 'italic' }}>Analysing nutritional risk...</span>
            </div>
          </div>
        )}
        <div ref={endRef} />
      </div>

      {/* Input */}
      <div style={{ padding: '0.75rem 1rem', background: 'white', borderTop: '1px solid #e5e7eb', borderRadius: '0 0 14px 14px' }}>
        <div style={{ display: 'flex', gap: 8 }}>
          <textarea
            value={input} onChange={e => setInput(e.target.value)}
            onKeyDown={e => { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); send(); } }}
            placeholder="Describe your symptoms... (e.g. I feel very tired, my nails are brittle and I have headaches)"
            rows={2} disabled={loading}
            style={{ flex: 1, padding: '0.65rem 1rem', border: '1.5px solid #e5e7eb', borderRadius: 10, fontFamily: 'Outfit, sans-serif', fontSize: '0.9rem', resize: 'none', outline: 'none', lineHeight: 1.5, transition: 'border-color 0.18s' }}
            onFocus={e => e.target.style.borderColor = '#16a34a'}
            onBlur={e => e.target.style.borderColor = '#e5e7eb'}
          />
          <button onClick={send} disabled={!input.trim() || loading} className="btn btn-primary" style={{ borderRadius: 10, padding: '0 1.25rem', flexShrink: 0 }}>
            Send →
          </button>
        </div>
        <div style={{ fontSize: '0.7rem', color: '#9ca3af', marginTop: 5 }}>
          Press Enter to send · AI guidance only · Not a substitute for medical advice
        </div>
      </div>
      <style>{`@keyframes bounce { 0%,100%{transform:translateY(0)} 50%{transform:translateY(-5px)} }`}</style>
    </div>
  );
}

// ── History ───────────────────────────────────────────────────────────────────
function History() {
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    api.get('/api/history').then(r => { setHistory(r.data); setLoading(false); }).catch(() => setLoading(false));
  }, []);

  if (loading) return <div style={{ textAlign: 'center', padding: '3rem' }}><span className="spinner" style={{ margin: '0 auto', display: 'block' }} /></div>;
  if (!history.length) return (
    <div style={{ textAlign: 'center', padding: '3rem', color: '#6b7280' }}>
      <div style={{ fontSize: '3rem', marginBottom: 12 }}>📋</div>
      <p>No analyses yet. Use the AI Chat to analyse your first symptoms!</p>
    </div>
  );

  return (
    <div>
      <h3 style={{ fontSize: '1.1rem', fontFamily: 'Outfit, sans-serif', fontWeight: 700, marginBottom: '1rem', color: '#374151' }}>Your Analysis History ({history.length})</h3>
      {history.map(h => (
        <div key={h.id} className="card" style={{ marginBottom: 12 }}>
          <div style={{ display: 'flex', justify: 'space-between', alignItems: 'flex-start', marginBottom: 8 }}>
            <div style={{ flex: 1 }}>
              <div style={{ fontSize: '0.8rem', color: '#6b7280', marginBottom: 4 }}>
                🕐 {new Date(h.timestamp).toLocaleString('en-KE')}
              </div>
              <div style={{ fontSize: '0.875rem', color: '#374151', fontStyle: 'italic', marginBottom: 8 }}>
                "{h.symptoms.length > 100 ? h.symptoms.substring(0, 100) + '...' : h.symptoms}"
              </div>
            </div>
          </div>
          {h.results?.length > 0 ? (
            <div style={{ display: 'flex', flexWrap: 'wrap', gap: 6 }}>
              {h.results.map(r => (
                <span key={r.id} style={{ display: 'inline-flex', alignItems: 'center', gap: 5, background: `${r.color}10`, color: r.color, border: `1px solid ${r.color}30`, borderRadius: 20, padding: '4px 12px', fontSize: '0.78rem', fontWeight: 600 }}>
                  {r.icon} {r.name} <strong>{r.confidence}%</strong>
                </span>
              ))}
            </div>
          ) : (
            <span style={{ fontSize: '0.78rem', color: '#6b7280' }}>No deficiencies identified</span>
          )}
        </div>
      ))}
    </div>
  );
}

// ── Hospital Map (OpenStreetMap) ───────────────────────────────────────────────
function HospitalMap() {
  const [hospitals, setHospitals] = useState([]);
  const [loading, setLoading] = useState(true);
  const [selected, setSelected] = useState(null);

  useEffect(() => {
    api.get('/api/hospitals').then(r => { setHospitals(r.data); setLoading(false); }).catch(() => setLoading(false));
  }, []);

  if (loading) return <div style={{ textAlign: 'center', padding: '3rem' }}><span className="spinner" style={{ margin: '0 auto', display: 'block' }} /></div>;

  const hospitalIcon = L.divIcon({
    html: `<div style="background:#16a34a;width:30px;height:30px;border-radius:50% 50% 50% 0;transform:rotate(-45deg);border:2px solid white;box-shadow:0 2px 8px rgba(0,0,0,0.3)"><div style="transform:rotate(45deg);text-align:center;line-height:26px;font-size:14px">🏥</div></div>`,
    className: '', iconSize: [30, 30], iconAnchor: [15, 30]
  });

  return (
    <div>
      <h3 style={{ fontSize: '1.1rem', fontFamily: 'Outfit, sans-serif', fontWeight: 700, marginBottom: '1rem', color: '#374151' }}>
        Nearby Hospitals & Facilities
      </h3>
      <div style={{ borderRadius: 12, overflow: 'hidden', border: '1px solid #e5e7eb', marginBottom: '1rem' }}>
        <MapContainer center={[-1.2921, 36.8219]} zoom={7} style={{ height: 380 }}>
          <TileLayer url="https://{s}.tile.openstreetmap.org/{z}/{x}/{y}.png" attribution="© OpenStreetMap contributors" />
          {hospitals.map(h => (
            <Marker key={h.id} position={[h.latitude, h.longitude]} icon={hospitalIcon} eventHandlers={{ click: () => setSelected(h) }}>
              <Popup>
                <strong>{h.name}</strong><br />
                {h.address}<br />
                <span style={{ color: '#16a34a' }}>📞 {h.phone}</span>
                {h.emergency ? <><br /><span style={{ color: '#dc2626', fontWeight: 700 }}>🚨 24hr Emergency</span></> : null}
              </Popup>
            </Marker>
          ))}
        </MapContainer>
      </div>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(280px, 1fr))', gap: 10 }}>
        {hospitals.map(h => (
          <div key={h.id} className="card" style={{ cursor: 'pointer', border: selected?.id === h.id ? '2px solid #16a34a' : '1px solid #e5e7eb', padding: '1rem' }} onClick={() => setSelected(h)}>
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: 6 }}>
              <div style={{ fontWeight: 700, fontSize: '0.9rem' }}>{h.name}</div>
              <div style={{ display: 'flex', gap: 4 }}>
                <span style={{ background: h.type === 'government' ? '#dbeafe' : '#dcfce7', color: h.type === 'government' ? '#1d4ed8' : '#16a34a', borderRadius: 8, padding: '2px 7px', fontSize: '0.65rem', fontWeight: 700, textTransform: 'uppercase' }}>{h.type}</span>
                {h.emergency ? <span style={{ background: '#fef2f2', color: '#dc2626', borderRadius: 8, padding: '2px 7px', fontSize: '0.65rem', fontWeight: 700 }}>24hr</span> : null}
              </div>
            </div>
            <div style={{ fontSize: '0.78rem', color: '#6b7280', marginBottom: 4 }}>📍 {h.address}</div>
            <div style={{ fontSize: '0.78rem', color: '#16a34a', fontWeight: 600 }}>📞 {h.phone}</div>
          </div>
        ))}
      </div>
    </div>
  );
}

// ── Profile ───────────────────────────────────────────────────────────────────
function Profile() {
  const { user, login, token } = useAuth();
  const [form, setForm] = useState({ name: user?.name || '', age: user?.age || '', blood_group: user?.blood_group || '', allergies: user?.allergies || '', chronic_conditions: user?.chronic_conditions || '' });
  const [saving, setSaving] = useState(false);
  const [msg, setMsg] = useState('');

  const set = k => e => setForm({ ...form, [k]: e.target.value });
  const handleSave = async e => {
    e.preventDefault(); setSaving(true); setMsg('');
    try {
      const res = await api.put('/api/profile', form);
      login(res.data, token);
      setMsg('Profile updated successfully!');
    } catch { setMsg('Failed to save. Please try again.'); } finally { setSaving(false); }
  };

  const BLOOD_GROUPS = ['A+', 'A-', 'B+', 'B-', 'AB+', 'AB-', 'O+', 'O-'];

  return (
    <div style={{ maxWidth: 480 }}>
      <h3 style={{ fontSize: '1.1rem', fontFamily: 'Outfit, sans-serif', fontWeight: 700, marginBottom: '1rem', color: '#374151' }}>My Health Profile</h3>
      {msg && <div className={`alert ${msg.includes('success') ? 'alert-success' : 'alert-error'}`}>{msg}</div>}
      <form onSubmit={handleSave} className="card">
        <div className="form-group">
          <label className="form-label">Full Name</label>
          <input className="form-input" value={form.name} onChange={set('name')} required />
        </div>
        <div className="grid-2">
          <div className="form-group">
            <label className="form-label">Age</label>
            <input type="number" className="form-input" value={form.age} onChange={set('age')} min="1" max="120" />
          </div>
          <div className="form-group">
            <label className="form-label">Blood Group</label>
            <select className="form-input" value={form.blood_group} onChange={set('blood_group')}>
              <option value="">Unknown</option>
              {BLOOD_GROUPS.map(b => <option key={b}>{b}</option>)}
            </select>
          </div>
        </div>
        <div className="form-group">
          <label className="form-label">Known Allergies</label>
          <input className="form-input" value={form.allergies} onChange={set('allergies')} placeholder="e.g. peanuts, shellfish" />
        </div>
        <div className="form-group">
          <label className="form-label">Chronic Conditions</label>
          <input className="form-input" value={form.chronic_conditions} onChange={set('chronic_conditions')} placeholder="e.g. diabetes, hypertension" />
        </div>
        <button type="submit" className="btn btn-primary" disabled={saving} style={{ width: '100%', justifyContent: 'center' }}>
          {saving ? 'Saving...' : 'Save Profile'}
        </button>
      </form>
      <div style={{ marginTop: '1rem', padding: '1rem', background: '#fef2f2', borderRadius: 10, fontSize: '0.78rem', color: '#6b7280' }}>
        <strong>Privacy:</strong> Your health data is stored securely, encrypted in transit, and never sold to third parties. You may delete your account at any time.
      </div>
    </div>
  );
}

// ── Dashboard Shell ───────────────────────────────────────────────────────────
const TABS = [
  { key: 'chat', label: '🩺 AI Chat' },
  { key: 'history', label: '📋 History' },
  { key: 'hospitals', label: '🏥 Hospitals' },
  { key: 'profile', label: '👤 Profile' },
];

export default function Dashboard() {
  const { user } = useAuth();
  const [tab, setTab] = useState('chat');

  return (
    <div style={{ maxWidth: 1100, margin: '0 auto', padding: '1.5rem 1.25rem' }}>
      {/* Welcome bar */}
      <div style={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', marginBottom: '1.25rem', flexWrap: 'wrap', gap: 8 }}>
        <div>
          <h2 style={{ fontSize: '1.4rem', marginBottom: 2 }}>Hello, {user?.name?.split(' ')[0]} 👋</h2>
          <p style={{ color: '#6b7280', fontSize: '0.875rem' }}>MediHelp AI Nutrition Dashboard</p>
        </div>
        <div style={{ display: 'flex', gap: 8, alignItems: 'center' }}>
          {user?.blood_group && (
            <span style={{ background: '#fef2f2', color: '#dc2626', border: '1px solid #fca5a5', borderRadius: 8, padding: '4px 10px', fontSize: '0.78rem', fontWeight: 700 }}>
              🩸 {user.blood_group}
            </span>
          )}
          {user?.allergies && (
            <span style={{ background: '#fffbeb', color: '#d97706', border: '1px solid #fcd34d', borderRadius: 8, padding: '4px 10px', fontSize: '0.78rem', fontWeight: 600 }}>
              ⚠️ {user.allergies}
            </span>
          )}
        </div>
      </div>

      {/* Tabs */}
      <div className="tabs">
        {TABS.map(t => (
          <button key={t.key} className={`tab ${tab === t.key ? 'active' : ''}`} onClick={() => setTab(t.key)}>
            {t.label}
          </button>
        ))}
      </div>

      {/* Content */}
      {tab === 'chat' && <Chatbot user={user} />}
      {tab === 'history' && <History />}
      {tab === 'hospitals' && <HospitalMap />}
      {tab === 'profile' && <Profile />}
    </div>
  );
}
